     5→import java.util.stream.Stream;
     6→
     7→/**
     8→ * Function to return a single stream of deriable items cast to a derived class or empty stream - filter and cast
     9→ * @param <T>
    10→ * @param <R>
    11→ */
    12→public class Narrow<T,R> implements Function<T,Stream<R>> {
    13→  private final Class<R> cls;
    14→  private Narrow( Class<R> cls) {
    15→    this.cls = Objects.requireNonNull(cls);
    16→  }
    17→  public static <T,R> Narrow<T,R> to( Class<R> cls) {
    18→    return new Narrow<T,R>(cls);
    19→  }
    20→  @Override
    21→  public Stream<R> apply(T item) {
    22→    return item != null && cls.isAssignableFrom(item.getClass()) ? Stream.of(cls.cast(item)): Stream.empty();
    23→  }
    24→}
