    26→/**
    27→ * Typed container for OWL restriction information. Replaces the string-based Map<String,
    28→ * List<String>> pattern.
    29→ * <p>
    30→ * This sealed interface provides a type-safe way to represent OWL restrictions, enabling
    31→ * compile-time checking and eliminating magic string comparisons.
    32→ */
    33→public sealed interface RestrictionInfo {
    34→
    35→  /**
    36→   * @return the original OWL object (class expression or data range)
    37→   */
    38→  Object expression();
    39→
    40→  /**
    41→   * @return cardinality value if this is a cardinality restriction
    42→   */
    43→  default OptionalInt cardinality() {
    44→    return OptionalInt.empty();
    45→  }
    46→
    47→  /**
    48→   * @return filler class/datatype if this is a value restriction
    49→   */
    50→  default Optional<? extends OWLPropertyRange> filler() {
    51→    return Optional.empty();
    52→  }
    53→
    54→  // Cardinality restrictions
    55→  record MinCardinality(OWLObjectMinCardinality expression) implements RestrictionInfo {
    56→
    57→    @Override
    58→    public OptionalInt cardinality() {
    59→      return OptionalInt.of(expression.getCardinality());
    60→    }
    61→  }
    62→
    63→  record MaxCardinality(OWLObjectMaxCardinality expression) implements RestrictionInfo {
    64→
    65→    @Override
    66→    public OptionalInt cardinality() {
    67→      return OptionalInt.of(expression.getCardinality());
    68→    }
    69→  }
    70→
    71→  record ExactCardinality(OWLObjectExactCardinality expression) implements RestrictionInfo {
    72→
    73→    @Override
    74→    public OptionalInt cardinality() {
    75→      return OptionalInt.of(expression.getCardinality());
    76→    }
    77→  }
    78→
    79→  // Data cardinality restrictions
    80→  record DataMinCardinality(OWLDataMinCardinality expression) implements RestrictionInfo {
    81→
    82→    @Override
    83→    public OptionalInt cardinality() {
    84→      return OptionalInt.of(expression.getCardinality());
    85→    }
    86→  }
    87→
    88→  record DataMaxCardinality(OWLDataMaxCardinality expression) implements RestrictionInfo {
    89→
    90→    @Override
    91→    public OptionalInt cardinality() {
    92→      return OptionalInt.of(expression.getCardinality());
    93→    }
    94→  }
    95→
    96→  record DataExactCardinality(OWLDataExactCardinality expression) implements RestrictionInfo {
    97→
    98→    @Override
    99→    public OptionalInt cardinality() {
   100→      return OptionalInt.of(expression.getCardinality());
   101→    }
   102→  }
   103→
   104→  // Value restrictions
   105→  record SomeValuesFrom(OWLObjectSomeValuesFrom expression) implements RestrictionInfo {
   106→
   107→    @Override
   108→    public Optional<OWLClassExpression> filler() {
   109→      return Optional.of(expression.getFiller());
   110→    }
   111→  }
   112→
   113→  record AllValuesFrom(OWLObjectAllValuesFrom expression) implements RestrictionInfo {
   114→
   115→    @Override
   116→    public Optional<OWLClassExpression> filler() {
   117→      return Optional.of(expression.getFiller());
   118→    }
   119→  }
   120→
   121→  record DataSomeValuesFrom(OWLDataSomeValuesFrom expression) implements RestrictionInfo {
   122→
   123→    @Override
   124→    public Optional<OWLDataRange> filler() {
   125→      return Optional.of(expression.getFiller());
   126→    }
   127→  }
   128→
   129→  record DataAllValuesFrom(OWLDataAllValuesFrom expression) implements RestrictionInfo {
   130→
   131→    @Override
   132→    public Optional<OWLDataRange> filler() {
   133→      return Optional.of(expression.getFiller());
   134→    }
   135→  }
   136→
   137→  // Other restrictions
   138→  record HasValue(OWLObjectHasValue expression) implements RestrictionInfo {
   139→
   140→  }
   141→
   142→  record DataHasValue(OWLDataHasValue expression) implements RestrictionInfo {
   143→
   144→  }
   145→
   146→  record OneOf(OWLObjectOneOf expression) implements RestrictionInfo {
   147→
   148→  }
   149→
   150→  record DataOneOf(OWLDataOneOf expression) implements RestrictionInfo {
   151→
   152→  }
   153→
   154→  record UnionOf(OWLObjectUnionOf expression) implements RestrictionInfo {
   155→
   156→  }
   157→
   158→  record IntersectionOf(OWLObjectIntersectionOf expression) implements RestrictionInfo {
   159→
   160→  }
   161→
   162→  record ComplementOf(OWLObjectComplementOf expression) implements RestrictionInfo {
   163→
   164→  }
   165→
   166→  /**
   167→   * Factory method to wrap an OWL class expression in the appropriate RestrictionInfo type. Uses
   168→   * pattern matching switch for concise type discrimination.
   169→   *
   170→   * @param expr the OWL class expression to wrap
   171→   * @return an Optional containing the appropriate RestrictionInfo subtype, or empty if
   172→   * unrecognized
   173→   */
   174→  static Optional<RestrictionInfo> from(OWLClassExpression expr) {
   175→    return Optional.ofNullable(switch (expr) {
   176→      case OWLObjectMinCardinality c -> new MinCardinality(c);
   177→      case OWLObjectMaxCardinality c -> new MaxCardinality(c);
   178→      case OWLObjectExactCardinality c -> new ExactCardinality(c);
   179→      case OWLObjectSomeValuesFrom c -> new SomeValuesFrom(c);
   180→      case OWLObjectAllValuesFrom c -> new AllValuesFrom(c);
   181→      case OWLObjectHasValue c -> new HasValue(c);
   182→      case OWLObjectOneOf c -> new OneOf(c);
   183→      case OWLObjectUnionOf c -> new UnionOf(c);
   184→      case OWLObjectIntersectionOf c -> new IntersectionOf(c);
   185→      case OWLObjectComplementOf c -> new ComplementOf(c);
   186→      case OWLDataMinCardinality c -> new DataMinCardinality(c);
   187→      case OWLDataMaxCardinality c -> new DataMaxCardinality(c);
   188→      case OWLDataExactCardinality c -> new DataExactCardinality(c);
   189→      case OWLDataSomeValuesFrom c -> new DataSomeValuesFrom(c);
   190→      case OWLDataAllValuesFrom c -> new DataAllValuesFrom(c);
   191→      case OWLDataHasValue c -> new DataHasValue(c);
   192→      case OWLDataOneOf c -> new DataOneOf(c);
   193→      default -> null;
   194→    });
   195→  }
   196→
   197→  /**
   198→   * Apply this restriction to an ArraySchema with correct OWL→OpenAPI semantics.
   199→   *
   200→   * @param schema the ArraySchema to apply restrictions to
   201→   */
   202→  default void applyToArraySchema(io.swagger.v3.oas.models.media.ArraySchema schema) {
   203→    switch (this) {
   204→      case MinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   205→      case MaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   206→      case ExactCardinality r -> {
   207→        schema.setMinItems(r.expression().getCardinality());
   208→        schema.setMaxItems(r.expression().getCardinality());
   209→      }
   210→      case DataMinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   211→      case DataMaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   212→      case DataExactCardinality r -> {
   213→        schema.setMinItems(r.expression().getCardinality());
   214→        schema.setMaxItems(r.expression().getCardinality());
   215→      }
   216→      case SomeValuesFrom r -> {
   217→        // someValuesFrom = "at least one from this set"
   218→        // Set minItems=1, NO maxItems
   219→        schema.setMinItems(1);
   220→      }
   221→      case AllValuesFrom r -> {
   222→        // allValuesFrom = type constraint only, NO cardinality
   223→        // Do nothing
   224→      }
   225→      case DataSomeValuesFrom r -> schema.setMinItems(1);
   226→      case DataAllValuesFrom r -> { /* type constraint only */ }
   227→      default -> { /* other restrictions don't affect array cardinality */ }
   228→    }
   229→  }
   230→
   231→  /**
   232→   * Check if this restriction implies the property is required (minCardinality >= 1).
   233→   *
   234→   * @return true if this restriction makes the property required
   235→   */
   236→  default boolean impliesRequired() {
   237→    return switch (this) {
   238→      case MinCardinality r -> r.expression().getCardinality() >= 1;
   239→      case ExactCardinality r -> r.expression().getCardinality() >= 1;
   240→      case DataMinCardinality r -> r.expression().getCardinality() >= 1;
   241→      case DataExactCardinality r -> r.expression().getCardinality() >= 1;
   242→      case SomeValuesFrom r -> true;
   243→      case DataSomeValuesFrom r -> true;
   244→      default -> false;
   245→    };
   246→  }
   247→
   248→  /**
   249→   * Check if this restriction implies an array (cardinality > 1 or someValuesFrom).
   250→   *
   251→   * @return true if this restriction implies an array property
   252→   */
   253→  default boolean impliesArray() {
   254→    return switch (this) {
   255→      case MinCardinality r -> r.expression().getCardinality() > 1;
   256→      case MaxCardinality r -> r.expression().getCardinality() > 1;
   257→      case ExactCardinality r -> r.expression().getCardinality() > 1;
   258→      case DataMinCardinality r -> r.expression().getCardinality() > 1;
   259→      case DataMaxCardinality r -> r.expression().getCardinality() > 1;
   260→      case DataExactCardinality r -> r.expression().getCardinality() > 1;
   261→      case SomeValuesFrom r -> true;
   262→      case DataSomeValuesFrom r -> true;
   263→      default -> false;
   264→    };
   265→  }
   266→
   267→  /**
   268→   * Extract enum literal values from DataOneOf restriction. Used to populate enum values in OpenAPI
   269→   * schema.
   270→   *
   271→   * @return list of literal string values, or empty list if not a DataOneOf restriction
   272→   */
   273→  default java.util.List<String> getEnumValues() {
   274→    return switch (this) {
   275→      case DataOneOf dataOneOf -> dataOneOf.expression().getValues().stream()
   276→          .map(org.semanticweb.owlapi.model.OWLLiteral::getLiteral)
   277→          .toList();
   278→      default -> java.util.List.of();
   279→    };
   280→  }
   281→
   282→  /**
   283→   * Extract range class names from value restrictions. Used to determine which classes/datatypes
   284→   * are referenced in restrictions.
   285→   *
   286→   * @param nameResolver property name resolver for IRI conversion
   287→   * @return list of range class/datatype names
   288→   */
   289→  default java.util.List<String> getRangeNames(
   290→      com.grl.component.schema.PropertyNameResolver nameResolver) {
   291→    return switch (this) {
   292→      case SomeValuesFrom r -> r.filler()
   293→          .filter(f -> f instanceof org.semanticweb.owlapi.model.OWLClass)
