    21→
    22→  private final Map<String, Schema<?>> schemaByRef = new ConcurrentSkipListMap<>(); // so we can safely computeIfAbsent
    23→  private final Set<String> computing = new HashSet<>();
    24→  private final String schemaLabel;
    25→
    26→  private final OWLClass apiRootClass;
    27→
    28→  private final Set<OWLClass> resourceClasses;
    29→
    30→  private final YamlConfig config;
    31→
    32→  public MappingContext(String defaultOntologyPrefixIRI, OWLOntology ontology, String schemaLabel,
    33→                        OWLClass apiRootClass, Set<OWLClass> resourceClasses, YamlConfig config) {
    34→    this.defaultOntologyPrefixIRI = defaultOntologyPrefixIRI;
    35→    this.ontology = ontology;
    36→    this.schemaLabel = schemaLabel;
    37→    this.apiRootClass = apiRootClass;
    38→    this.resourceClasses = Collections.unmodifiableSet(resourceClasses);
    39→    this.config = config;
    40→  }
    41→
    42→  public YamlConfig getConfig() {
    43→    return config;
    44→  }
    45→
    46→  public OWLClass getApiRootClass() {
    47→    return apiRootClass;
    48→  }
    49→
    50→  public String getDefaultOntologyPrefixIRI() {
    51→    return defaultOntologyPrefixIRI;
    52→  }
    53→
    54→  public IRI localIRI(String shortForm) {
    55→    return IRI.create(defaultOntologyPrefixIRI, shortForm);
    56→  }
    57→  public OWLOntology getOntology() {
    58→    return ontology;
    59→  }
    60→
    61→
    62→  public String getSchemaLabel() {
    63→    return schemaLabel;
    64→  }
    65→
    66→  public Map<String, Schema<?>> getSchemaByRef() {
    67→    return schemaByRef;
    68→  }
    69→
    70→  public OWLOntologyManager getManager() {
    71→    return manager;
    72→  }
    73→
    74→
    75→  /**
    76→   * If not in context cache already, create schema for given class and add to cache
    77→   *
    78→   * @param shortName shortname of class
    79→   */
    80→  public void addSchema(String shortName) {
    81→    schemaByRef.computeIfAbsent(shortName, s -> {
    82→      if (!computing.contains(s)) {
    83→        computing.add(s);
    84→        OWLClass cls = manager.getOWLDataFactory().getOWLClass(IRI.create(defaultOntologyPrefixIRI + shortName));
    85→        String description = OntologyUtil.getDescription(cls, ontology);
    86→        ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
    87→        computing.remove(s);
    88→        return resourceSchemaMapper.getSchema();
    89→      } else
    90→        return null; // already being computed, ignore to avoid infinite recursion
    91→    });
    92→  }
    93→
    94→  public Set<OWLClass> getResourceClasses() {
    95→    return resourceClasses;
    96→  }
    97→
    98→
    99→}
